{
  "name": "RotoTranslaViz",
  "description": "A 3D visualization tool for computing and viewing rigid body transformations (Rotation and Translation) in Fixed and Mobile frames."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { Matrix4 } from 'three';

export type Axis = 'x' | 'y' | 'z';
export type FrameType = 'fixed' | 'mobile';
export type OperationType = 'rotation' | 'translation';

export interface TransformationStep {
  id: string;
  type: OperationType;
  axis: Axis;
  value: number; // Degrees for rotation, Units for translation
  frame: FrameType;
  stepMatrix: Matrix4; // The matrix representing ONLY this change
  cumulativeMatrix: Matrix4; // The matrix representing Initial -> After this step
}

import React from 'react';
import { Matrix4 } from 'three';

interface MatrixDisplayProps {
  matrix: Matrix4;
  title?: string;
  className?: string;
  highlight?: boolean;
}

export const MatrixDisplay: React.FC<MatrixDisplayProps> = ({ matrix, title, className = "", highlight = false }) => {
  const elements = matrix.elements; 
  // Three.js stores matrices in column-major order.
  // We need to read them as rows for display: [0, 4, 8, 12], [1, 5, 9, 13], etc.

  const rows = [0, 1, 2, 3].map(row => 
    [0, 1, 2, 3].map(col => elements[row + col * 4])
  );

  return (
    <div className={`p-3 bg-slate-800 rounded-lg border ${highlight ? 'border-blue-500 shadow-lg shadow-blue-500/20' : 'border-slate-700'} ${className}`}>
      {title && <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 text-center">{title}</h4>}
      <div className="grid grid-cols-4 gap-1 font-mono text-xs sm:text-sm">
        {rows.map((row, rIndex) => (
          <React.Fragment key={rIndex}>
            {row.map((val, cIndex) => (
              <div 
                key={`${rIndex}-${cIndex}`} 
                className={`
                  flex items-center justify-center p-1 rounded
                  ${rIndex < 3 && cIndex < 3 ? 'bg-slate-700/50 text-slate-200' : ''} 
                  ${rIndex < 3 && cIndex === 3 ? 'bg-indigo-900/30 text-indigo-300' : ''}
                  ${rIndex === 3 ? 'bg-slate-900/50 text-slate-500' : ''}
                `}
              >
                {val.toFixed(2)}
              </div>
            ))}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, GizmoHelper, GizmoViewport } from '@react-three/drei';
import * as THREE from 'three';

interface SceneProps {
  currentMatrix: THREE.Matrix4;
}

const MovingFrame: React.FC<{ matrix: THREE.Matrix4 }> = ({ matrix }) => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame(() => {
    if (groupRef.current) {
      // Decompose the matrix to apply it smoothly or directly set it
      // For immediate feedback, we decompose position, quaternion, scale
      const pos = new THREE.Vector3();
      const quat = new THREE.Quaternion();
      const scale = new THREE.Vector3();

      matrix.decompose(pos, quat, scale);

      // Lerp for smooth animation could go here, but for scientific precision
      // we snap to the exact pose
      groupRef.current.position.copy(pos);
      groupRef.current.quaternion.copy(quat);
      groupRef.current.scale.copy(scale);
    }
  });

  return (
    <group ref={groupRef}>
      {/* Local Axes */}
      <axesHelper args={[2]} />
      {/* Origin Sphere */}
      <mesh>
        <sphereGeometry args={[0.1, 16, 16]} />
        <meshStandardMaterial color="white" />
      </mesh>
      {/* Label */}
      <group position={[0, 2.2, 0]}>
         {/* Simple visual marker for top of frame */}
      </group>
    </group>
  );
};

export const Scene: React.FC<SceneProps> = ({ currentMatrix }) => {
  return (
    <div className="w-full h-full bg-slate-900 rounded-xl overflow-hidden shadow-inner shadow-black/50 border border-slate-700">
      <Canvas>
        <PerspectiveCamera makeDefault position={[5, 5, 5]} fov={50} />
        <OrbitControls makeDefault />
        <ambientLight intensity={0.5} />
        <pointLight position={[10, 10, 10]} intensity={1} />

        {/* Fixed World Frame Reference */}
        <group>
          <Grid infiniteGrid fadeDistance={30} sectionColor="#475569" cellColor="#1e293b" />
          <axesHelper args={[1]} position={[0, 0.01, 0]}  /> 
          <mesh position={[0, 0, 0]}>
            <sphereGeometry args={[0.05, 16, 16]} />
            <meshBasicMaterial color="#64748b" />
          </mesh>
        </group>

        {/* The User's Mobile Frame */}
        <MovingFrame matrix={currentMatrix} />

        <GizmoHelper alignment="bottom-right" margin={[80, 80]}>
          <GizmoViewport axisColors={['#ef4444', '#22c55e', '#3b82f6']} labelColor="white" />
        </GizmoHelper>
      </Canvas>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Matrix4, Vector3, Quaternion, Euler, MathUtils } from 'three';
import { Plus, RotateCw, Move3d, Undo2, Trash2, ArrowRightLeft, Calculator, Info } from 'lucide-react';
import { Scene } from './components/Scene';
import { MatrixDisplay } from './components/MatrixDisplay';
import { TransformationStep, Axis, FrameType, OperationType } from './types';

// Constants
const AXIS_VECTORS: Record<Axis, Vector3> = {
  x: new Vector3(1, 0, 0),
  y: new Vector3(0, 1, 0),
  z: new Vector3(0, 0, 1),
};

const App: React.FC = () => {
  // State
  const [steps, setSteps] = useState<TransformationStep[]>([]);

  // Input State
  const [opType, setOpType] = useState<OperationType>('rotation');
  const [axis, setAxis] = useState<Axis>('x');
  const [frame, setFrame] = useState<FrameType>('mobile');
  const [value, setValue] = useState<number>(90); // Default 90 deg or 1 unit

  // Derived State: Current Matrix
  const currentMatrix = useMemo(() => {
    if (steps.length === 0) return new Matrix4();
    return steps[steps.length - 1].cumulativeMatrix;
  }, [steps]);

  // Modal State
  const [showResult, setShowResult] = useState<'none' | 'final' | 'inverse'>('none');

  const handleAddStep = () => {
    const newStepMatrix = new Matrix4();

    // 1. Calculate the Transformation Matrix for THIS step
    if (opType === 'rotation') {
      const radians = MathUtils.degToRad(value);
      if (axis === 'x') newStepMatrix.makeRotationX(radians);
      if (axis === 'y') newStepMatrix.makeRotationY(radians);
      if (axis === 'z') newStepMatrix.makeRotationZ(radians);
    } else {
      if (axis === 'x') newStepMatrix.makeTranslation(value, 0, 0);
      if (axis === 'y') newStepMatrix.makeTranslation(0, value, 0);
      if (axis === 'z') newStepMatrix.makeTranslation(0, 0, value);
    }

    // 2. Calculate Cumulative Matrix
    const prevMatrix = steps.length > 0 ? steps[steps.length - 1].cumulativeMatrix.clone() : new Matrix4();
    const newCumulative = prevMatrix.clone();

    if (frame === 'mobile') {
      // Post-multiply for Mobile/Local frame
      newCumulative.multiply(newStepMatrix);
    } else {
      // Pre-multiply for Fixed/World frame
      newCumulative.premultiply(newStepMatrix);
    }

    const newStep: TransformationStep = {
      id: Math.random().toString(36).substr(2, 9),
      type: opType,
      axis,
      value,
      frame,
      stepMatrix: newStepMatrix,
      cumulativeMatrix: newCumulative,
    };

    setSteps([...steps, newStep]);
  };

  const handleUndo = () => {
    setSteps(prev => prev.slice(0, -1));
  };

  const handleReset = () => {
    setSteps([]);
  };

  const getInverseMatrix = () => {
    const inv = currentMatrix.clone().invert();
    return inv;
  };

  return (
    <div className="flex flex-col h-full md:flex-row max-w-7xl mx-auto overflow-hidden">

      {/* Left / Top Panel: 3D Workspace */}
      <div className="relative w-full h-[45vh] md:h-full md:w-1/2 lg:w-3/5 p-4 flex flex-col">
         <header className="mb-2 flex justify-between items-center">
            <div>
              <h1 className="text-xl font-bold text-white flex items-center gap-2">
                <Move3d className="w-6 h-6 text-blue-400" /> 
                RotoTranslaViz
              </h1>
              <p className="text-xs text-slate-400">Fixed & Mobile Frame Visualizer</p>
            </div>
            <div className="flex gap-2">
               {steps.length > 0 && (
                 <button onClick={handleReset} className="p-2 hover:bg-red-900/50 text-red-400 rounded transition-colors" title="Reset All">
                    <Trash2 size={18} />
                 </button>
               )}
            </div>
         </header>

         <div className="flex-grow relative">
            <Scene currentMatrix={currentMatrix} />

            {/* Overlay indicators */}
            <div className="absolute top-4 left-4 pointer-events-none">
              <div className="bg-slate-900/80 backdrop-blur px-3 py-1.5 rounded border border-slate-700 text-xs text-slate-300">
                <div className="flex items-center gap-2 mb-1">
                   <span className="w-2 h-2 rounded-full bg-slate-500"></span> Fixed (World)
                </div>
                <div className="flex items-center gap-2">
                   <span className="w-2 h-2 rounded-full bg-gradient-to-r from-red-500 via-green-500 to-blue-500"></span> Mobile (Current)
                </div>
              </div>
            </div>
         </div>
      </div>

      {/* Right / Bottom Panel: Controls & History */}
      <div className="w-full h-[55vh] md:h-full md:w-1/2 lg:w-2/5 bg-slate-900/50 border-t md:border-t-0 md:border-l border-slate-800 flex flex-col">

        {/* Controls Section */}
        <div className="p-4 border-b border-slate-800 bg-slate-900">
          <h2 className="text-sm font-semibold text-slate-300 mb-3 uppercase tracking-wider">New Transformation</h2>

          <div className="grid grid-cols-2 gap-3 mb-3">
             {/* Operation Type */}
             <div className="flex bg-slate-800 p-1 rounded-lg">
                <button 
                  onClick={() => setOpType('rotation')}
                  className={`flex-1 flex items-center justify-center gap-2 py-1.5 text-xs font-medium rounded ${opType === 'rotation' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                  <RotateCw size={14} /> Rotation
                </button>
                <button 
                  onClick={() => setOpType('translation')}
                  className={`flex-1 flex items-center justify-center gap-2 py-1.5 text-xs font-medium rounded ${opType === 'translation' ? 'bg-green-600 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                  <ArrowRightLeft size={14} /> Translation
                </button>
             </div>

             {/* Frame Type */}
             <div className="flex bg-slate-800 p-1 rounded-lg">
                <button 
                  onClick={() => setFrame('fixed')}
                  className={`flex-1 py-1.5 text-xs font-medium rounded ${frame === 'fixed' ? 'bg-slate-600 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                  Fixed (XYZ)
                </button>
                <button 
                  onClick={() => setFrame('mobile')}
                  className={`flex-1 py-1.5 text-xs font-medium rounded ${frame === 'mobile' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                  Mobile (x'y'z')
                </button>
             </div>
          </div>

          <div className="grid grid-cols-12 gap-3 items-end">
             {/* Axis Selection */}
             <div className="col-span-4">
               <label className="block text-xs text-slate-500 mb-1">Axis</label>
               <div className="flex gap-1">
                 {(['x', 'y', 'z'] as Axis[]).map((a) => (
                   <button
                    key={a}
                    onClick={() => setAxis(a)}
                    className={`flex-1 h-9 rounded font-bold uppercase text-sm border-b-2 transition-all
                      ${axis === a && a === 'x' ? 'bg-red-500/20 text-red-400 border-red-500' : ''}
                      ${axis === a && a === 'y' ? 'bg-green-500/20 text-green-400 border-green-500' : ''}
                      ${axis === a && a === 'z' ? 'bg-blue-500/20 text-blue-400 border-blue-500' : ''}
                      ${axis !== a ? 'bg-slate-800 border-transparent text-slate-500 hover:bg-slate-700' : ''}
                    `}
                   >
                     {a}
                   </button>
                 ))}
               </div>
             </div>

             {/* Value Input */}
             <div className="col-span-4">
                <label className="block text-xs text-slate-500 mb-1">
                  {opType === 'rotation' ? 'Angle (deg)' : 'Distance'}
                </label>
                <input 
                  type="number" 
                  value={value}
                  onChange={(e) => setValue(parseFloat(e.target.value) || 0)}
                  className="w-full h-9 bg-slate-800 border border-slate-700 rounded px-3 text-sm text-white focus:outline-none focus:border-blue-500"
                />
             </div>

             {/* Action Button */}
             <div className="col-span-4">
               <button 
                onClick={handleAddStep}
                className="w-full h-9 bg-blue-600 hover:bg-blue-500 text-white font-medium rounded flex items-center justify-center gap-2 transition-colors shadow-lg shadow-blue-900/20"
               >
                 <Plus size={16} /> Apply
               </button>
             </div>
          </div>
        </div>

        {/* History List */}
        <div className="flex-grow overflow-y-auto p-4 space-y-4">
          <div className="flex justify-between items-center mb-2">
             <h2 className="text-sm font-semibold text-slate-300 uppercase tracking-wider">Transformation History</h2>
             {steps.length > 0 && (
                <button onClick={handleUndo} className="flex items-center gap-1 text-xs text-slate-400 hover:text-white transition-colors">
                  <Undo2 size={12} /> Undo Last
                </button>
             )}
          </div>

          {steps.length === 0 ? (
             <div className="text-center py-10 text-slate-600 italic text-sm">
               No transformations applied yet.<br/>The system is at Identity.
             </div>
          ) : (
            steps.map((step, index) => (
              <div key={step.id} className="relative group">
                 {/* Connection Line */}
                 {index < steps.length - 1 && (
                   <div className="absolute left-4 top-10 bottom-[-16px] w-0.5 bg-slate-800"></div>
                 )}

                 <div className="bg-slate-800/50 rounded-lg p-3 border border-slate-700/50 hover:border-slate-600 transition-colors">
                    <div className="flex items-center justify-between mb-2">
                       <div className="flex items-center gap-3">
                          <div className={`
                             w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold
                             ${step.type === 'rotation' ? 'bg-blue-900/50 text-blue-300' : 'bg-green-900/50 text-green-300'}
                          `}>
                            {index + 1}
                          </div>
                          <div>
                            <div className="text-sm font-medium text-slate-200">
                               {step.type === 'rotation' ? 'Rot' : 'Trans'}({step.axis.toUpperCase()}, {step.value}{step.type === 'rotation' ? '°' : ''})
                            </div>
                            <div className="text-xs text-slate-500">
                               in {step.frame === 'fixed' ? 'Fixed (XYZ)' : "Mobile (x'y'z')"} frame
                            </div>
                          </div>
                       </div>
                    </div>
                    {/* Matrix for this step */}
                    <MatrixDisplay matrix={step.stepMatrix} title="Step Matrix" className="bg-slate-900/80" />
                 </div>
              </div>
            ))
          )}
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-slate-800 bg-slate-900 grid grid-cols-2 gap-3">
           <button 
             disabled={steps.length === 0}
             onClick={() => setShowResult('final')}
             className="flex items-center justify-center gap-2 py-2.5 rounded bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-medium disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
           >
             <Info size={14} /> Total Matrix (T)
           </button>
           <button 
             disabled={steps.length === 0}
             onClick={() => setShowResult('inverse')}
             className="flex items-center justify-center gap-2 py-2.5 rounded bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-medium disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
           >
             <Calculator size={14} /> Inverse Matrix (T⁻¹)
           </button>
        </div>
      </div>

      {/* Result Modal */}
      {showResult !== 'none' && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4">
           <div className="bg-slate-900 border border-slate-700 rounded-xl shadow-2xl max-w-md w-full overflow-hidden">
              <div className="p-4 border-b border-slate-800 flex justify-between items-center">
                <h3 className="text-lg font-bold text-white">
                  {showResult === 'final' ? 'Total Transformation Matrix' : 'Inverse Transformation Matrix'}
                </h3>
                <button onClick={() => setShowResult('none')} className="text-slate-400 hover:text-white">✕</button>
              </div>

              <div className="p-6">
                <p className="text-sm text-slate-400 mb-4">
                  {showResult === 'final' 
                    ? 'This matrix represents the final pose with respect to the initial (0,0,0) coordinate system.' 
                    : 'This matrix allows you to calculate the Initial pose with respect to the Final frame (reverses the transformation).'}
                </p>
                <MatrixDisplay 
                  matrix={showResult === 'final' ? currentMatrix : getInverseMatrix()} 
                  highlight 
                  className="bg-slate-800"
                />
              </div>

              <div className="p-4 bg-slate-950 border-t border-slate-800 text-right">
                <button 
                  onClick={() => setShowResult('none')}
                  className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded text-sm font-medium transition-colors"
                >
                  Close
                </button>
              </div>
           </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React from 'react';
import { Matrix4 } from 'three';

interface MatrixDisplayProps {
  matrix: Matrix4;
  title?: string;
  className?: string;
  highlight?: boolean;
}

export const MatrixDisplay: React.FC<MatrixDisplayProps> = ({ matrix, title, className = "", highlight = false }) => {
  const elements = matrix.elements; 
  // Three.js stores matrices in column-major order.
  // We need to read them as rows for display: [0, 4, 8, 12], [1, 5, 9, 13], etc.

  const rows = [0, 1, 2, 3].map(row => 
    [0, 1, 2, 3].map(col => elements[row + col * 4])
  );

  const formatValue = (val: number) => {
    // Avoid -0 or -0.00
    if (Math.abs(val) < 0.005) return "0.00";
    return val.toFixed(2);
  };

  return (
    <div className={`p-3 bg-slate-800 rounded-lg border ${highlight ? 'border-blue-500 shadow-lg shadow-blue-500/20' : 'border-slate-700'} ${className}`}>
      {title && <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 text-center">{title}</h4>}
      <div className="grid grid-cols-4 gap-1 font-mono text-xs sm:text-sm">
        {rows.map((row, rIndex) => (
          <React.Fragment key={rIndex}>
            {row.map((val, cIndex) => (
              <div 
                key={`${rIndex}-${cIndex}`} 
                className={`
                  flex items-center justify-center p-1 rounded
                  ${rIndex < 3 && cIndex < 3 ? 'bg-slate-700/50 text-slate-200' : ''} 
                  ${rIndex < 3 && cIndex === 3 ? 'bg-indigo-900/30 text-indigo-300' : ''}
                  ${rIndex === 3 ? 'bg-slate-900/50 text-slate-500' : ''}
                `}
              >
                {formatValue(val)}
              </div>
            ))}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
};

import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, GizmoHelper, GizmoViewport, Text, Html } from '@react-three/drei';
import * as THREE from 'three';

interface SceneProps {
  matrices: THREE.Matrix4[];
}

const FrameAxis: React.FC<{ 
  dir: THREE.Vector3, 
  color: string, 
  label: string, 
  length?: number 
}> = ({ dir, color, label, length = 1.5 }) => {
  // Use a small offset for the text so it doesn't overlap the line exactly
  const textPos = dir.clone().multiplyScalar(length + 0.2);

  return (
    <group>
      <arrowHelper args={[dir, new THREE.Vector3(0,0,0), length, color, 0.2, 0.1]} />
      <Text
        position={textPos}
        fontSize={0.2}
        color={color}
        anchorX="center"
        anchorY="middle"
      >
        {label}
      </Text>
    </group>
  );
};

const CoordinateFrame: React.FC<{ 
  matrix: THREE.Matrix4; 
  index: number; 
  isLast: boolean; 
  isFirst: boolean;
}> = ({ matrix, index, isLast, isFirst }) => {
  const groupRef = useRef<THREE.Group>(null);

  // Define colors based on index to differentiate frames
  // Frame 0: Standard primary colors
  // Others: Slightly different shades or keep standard but rely on labels
  // The user asked to "differentiate colors". 
  // We keep Axis colors standard (RGB) for consistency in direction, 
  // but we can tint the origin or labels.

  const originColor = isFirst ? '#ffffff' : (isLast ? '#fbbf24' : '#94a3b8'); // White for 0, Amber for Last, Slate for others
  const opacity = isLast || isFirst ? 1 : 0.4;
  const scale = isLast || isFirst ? 1 : 0.8;

  useFrame(() => {
    if (groupRef.current) {
      const pos = new THREE.Vector3();
      const quat = new THREE.Quaternion();
      const s = new THREE.Vector3();
      matrix.decompose(pos, quat, s);
      groupRef.current.position.copy(pos);
      groupRef.current.quaternion.copy(quat);
    }
  });

  return (
    <group ref={groupRef} scale={[scale, scale, scale]}>
      {/* Origin Sphere */}
      <mesh>
        <sphereGeometry args={[isFirst ? 0.08 : 0.05, 16, 16]} />
        <meshStandardMaterial color={originColor} transparent opacity={opacity} />
      </mesh>

      {/* Axes */}
      <FrameAxis dir={new THREE.Vector3(1,0,0)} color={isFirst ? "#ff0000" : "#ff6b6b"} label={`x${index}`} length={isFirst ? 2 : 1.5} />
      <FrameAxis dir={new THREE.Vector3(0,1,0)} color={isFirst ? "#00ff00" : "#51cf66"} label={`y${index}`} length={isFirst ? 2 : 1.5} />
      <FrameAxis dir={new THREE.Vector3(0,0,1)} color={isFirst ? "#0000ff" : "#339af0"} label={`z${index}`} length={isFirst ? 2 : 1.5} />

      {/* Origin Label */}
      <Text
        position={[0.2, 0.2, 0.2]}
        fontSize={0.25}
        color={originColor}
        anchorX="left"
        anchorY="bottom"
      >
        {`O${index}`}
      </Text>
    </group>
  );
};

const TrajectoryLines: React.FC<{ matrices: THREE.Matrix4[] }> = ({ matrices }) => {
  const points = useMemo(() => {
    return matrices.map(m => {
      const pos = new THREE.Vector3();
      const q = new THREE.Quaternion();
      const s = new THREE.Vector3();
      m.decompose(pos, q, s);
      return pos;
    });
  }, [matrices]);

  if (points.length < 2) return null;

  // Create a line geometry
  const geometry = new THREE.BufferGeometry().setFromPoints(points);

  return (
    <line geometry={geometry}>
      <lineBasicMaterial color="#fbbf24" opacity={0.5} transparent dashSize={0.2} gapSize={0.1} />
    </line>
  );
};

export const Scene: React.FC<SceneProps> = ({ matrices }) => {
  return (
    <div className="w-full h-full bg-slate-900 rounded-xl overflow-hidden shadow-inner shadow-black/50 border border-slate-700">
      <Canvas>
        {/* Fixed Camera position, locked controls */}
        <PerspectiveCamera makeDefault position={[6, 5, 8]} fov={45} />
        <OrbitControls 
          enableRotate={false} 
          enableZoom={true} 
          enablePan={true}
          makeDefault 
        />

        <ambientLight intensity={0.6} />
        <pointLight position={[10, 10, 10]} intensity={1} />

        {/* World Grid for context */}
        <Grid infiniteGrid fadeDistance={25} sectionColor="#334155" cellColor="#1e293b" position={[0, -0.01, 0]} />

        {/* Render all frames in history */}
        {matrices.map((matrix, i) => (
          <CoordinateFrame 
            key={i} 
            matrix={matrix} 
            index={i} 
            isFirst={i === 0}
            isLast={i === matrices.length - 1} 
          />
        ))}

        {/* Trajectory Line connecting origins */}
        <TrajectoryLines matrices={matrices} />

        <GizmoHelper alignment="bottom-right" margin={[80, 80]}>
          <GizmoViewport axisColors={['#ef4444', '#22c55e', '#3b82f6']} labelColor="white" />
        </GizmoHelper>
      </Canvas>
    </div>
  );
