import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, GizmoHelper, GizmoViewport, Text, Html, Line } from '@react-three/drei';
import * as THREE from 'three';

interface SceneProps {
  matrices: THREE.Matrix4[];
}

const FrameAxis: React.FC<{ 
  dir: THREE.Vector3, 
  color: string, 
  label: string, 
  length?: number 
}> = ({ dir, color, label, length = 1.5 }) => {
  // Use a small offset for the text so it doesn't overlap the line exactly
  const textPos = dir.clone().multiplyScalar(length + 0.2);

  return (
    <group>
      <arrowHelper args={[dir, new THREE.Vector3(0,0,0), length, color, 0.2, 0.1]} />
      <Text
        position={textPos}
        fontSize={0.2}
        color={color}
        anchorX="center"
        anchorY="middle"
      >
        {label}
      </Text>
    </group>
  );
};

const CoordinateFrame: React.FC<{ 
  matrix: THREE.Matrix4; 
  index: number; 
  isLast: boolean; 
  isFirst: boolean;
}> = ({ matrix, index, isLast, isFirst }) => {
  const groupRef = useRef<THREE.Group>(null);

  // Define colors based on index to differentiate frames
  // Frame 0: Standard primary colors
  // Others: Slightly different shades or keep standard but rely on labels
  // The user asked to "differentiate colors". 
  // We keep Axis colors standard (RGB) for consistency in direction, 
  // but we can tint the origin or labels.

  const originColor = isFirst ? '#ffffff' : (isLast ? '#fbbf24' : '#94a3b8'); // White for 0, Amber for Last, Slate for others
  const opacity = isLast || isFirst ? 1 : 0.4;
  const scale = isLast || isFirst ? 1 : 0.8;

  useFrame(() => {
    if (groupRef.current) {
      const pos = new THREE.Vector3();
      const quat = new THREE.Quaternion();
      const s = new THREE.Vector3();
      matrix.decompose(pos, quat, s);
      groupRef.current.position.copy(pos);
      groupRef.current.quaternion.copy(quat);
    }
  });

  return (
    <group ref={groupRef} scale={[scale, scale, scale]}>
      {/* Origin Sphere */}
      <mesh>
        <sphereGeometry args={[isFirst ? 0.08 : 0.05, 16, 16]} />
        <meshStandardMaterial color={originColor} transparent opacity={opacity} />
      </mesh>

      {/* Axes */}
      <FrameAxis dir={new THREE.Vector3(1,0,0)} color={isFirst ? "#ff0000" : "#ff6b6b"} label={`x${index}`} length={isFirst ? 2 : 1.5} />
      <FrameAxis dir={new THREE.Vector3(0,1,0)} color={isFirst ? "#00ff00" : "#51cf66"} label={`y${index}`} length={isFirst ? 2 : 1.5} />
      <FrameAxis dir={new THREE.Vector3(0,0,1)} color={isFirst ? "#0000ff" : "#339af0"} label={`z${index}`} length={isFirst ? 2 : 1.5} />

      {/* Origin Label */}
      <Text
        position={[0.2, 0.2, 0.2]}
        fontSize={0.25}
        color={originColor}
        anchorX="left"
        anchorY="bottom"
      >
        {`O${index}`}
      </Text>
    </group>
  );
};

const TrajectoryLines: React.FC<{ matrices: THREE.Matrix4[] }> = ({ matrices }) => {
  const points = useMemo(() => {
    return matrices.map(m => {
      const pos = new THREE.Vector3();
      const q = new THREE.Quaternion();
      const s = new THREE.Vector3();
      m.decompose(pos, q, s);
      return pos;
    });
  }, [matrices]);

  if (points.length < 2) return null;

  return (
    <Line
      points={points}
      color="#fbbf24"
      opacity={0.5}
      transparent
      dashed
      dashSize={0.2}
      gapSize={0.1}
      lineWidth={1}
    />
  );
};

export const Scene: React.FC<SceneProps> = ({ matrices }) => {
  return (
    <div className="w-full h-full bg-slate-900 rounded-xl overflow-hidden shadow-inner shadow-black/50 border border-slate-700">
      <Canvas>
        {/* Fixed Camera position, locked controls */}
        <PerspectiveCamera makeDefault position={[6, 5, 8]} fov={45} />
        <OrbitControls 
          enableRotate={false} 
          enableZoom={true} 
          enablePan={true}
          makeDefault 
        />

        <ambientLight intensity={0.6} />
        <pointLight position={[10, 10, 10]} intensity={1} />

        {/* World Grid for context */}
        <Grid infiniteGrid fadeDistance={25} sectionColor="#334155" cellColor="#1e293b" position={[0, -0.01, 0]} />

        {/* Render all frames in history */}
        {matrices.map((matrix, i) => (
          <CoordinateFrame 
            key={i} 
            matrix={matrix} 
            index={i} 
            isFirst={i === 0}
            isLast={i === matrices.length - 1} 
